tool.command:
@CMD_UNZIP_ZARR@
mkdir -p output_dir &&
## Run aggregation sopa aggregate $aggregate_genes $aggregate_channels #if $expand_radius_ratio --expand-radius-ratio $expand_radius_ratio #end if --min-transcripts $min_transcripts --min-intensity-ratio $min_intensity_ratio #if str($image_key) != '' --image-key '$image_key' #end if #if str($gene_column) != '' --gene-column '$gene_column' #end if input/spatialdata.zarr &&
## Move to output directory mv input/spatialdata.zarr output_dir/ &&
@CMD_ZIP_ZARR@
